import heapq

class Solution:
    def minimumCost(self, source, target, original, changed, cost):
        n = len(source)
        node_id = {}
        def get_id(x):
            if x not in node_id:
                node_id[x] = len(node_id)
            return node_id[x]
        adj = {}
        lengths = set()
        m = len(cost)
        for j in range(m):
            u = get_id(original[j])
            v = get_id(changed[j])
            w = cost[j]
            adj.setdefault(u, []).append((v, w))
            lengths.add(len(original[j]))
        num_nodes = len(node_id)
        INF = float('inf')
        dist_from = []
        for start in range(num_nodes):
            dist = [INF] * num_nodes
            dist[start] = 0
            pq = [(0, start)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                for v, w in adj.get(u, []):
                    nd = d + w
                    if nd < dist[v]:
                        dist[v] = nd
                        heapq.heappush(pq, (nd, v))
            dist_from.append(dist)
        lengths = sorted(lengths)
        dp = [INF] * (n + 1)
        dp[0] = 0
        for i in range(n):
            if dp[i] == INF:
                continue
            if source[i] == target[i] and dp[i] < dp[i + 1]:
                dp[i + 1] = dp[i]
            for L in lengths:
                if i + L > n:
                    continue
                sub_s = source[i:i + L]
                sub_t = target[i:i + L]
                if sub_s in node_id and sub_t in node_id:
                    u = node_id[sub_s]
                    v = node_id[sub_t]
                    d = dist_from[u][v]
                    if d < INF and dp[i] + d < dp[i + L]:
                        dp[i + L] = dp[i] + d
        return dp[n] if dp[n] < INF else -1

