var minimumCost = function(source, target, original, changed, cost) {
    const n = source.length;
    const nodeId = new Map();
    function getId(x) {
        if (!nodeId.has(x)) nodeId.set(x, nodeId.size);
        return nodeId.get(x);
    }
    const m = cost.length;
    const edges = [];
    const lengthsSet = new Set();
    for (let j = 0; j < m; j++) {
        const u = getId(original[j]);
        const v = getId(changed[j]);
        edges.push([u, v, cost[j]]);
        lengthsSet.add(original[j].length);
    }
    const k = nodeId.size;
    const INF = Infinity;
    const dist = [];
    for (let i = 0; i < k; i++) {
        dist.push(new Array(k).fill(INF));
        dist[i][i] = 0;
    }
    for (const [u, v, w] of edges) {
        if (w < dist[u][v]) dist[u][v] = w;
    }
    for (let mid = 0; mid < k; mid++) {
        for (let i = 0; i < k; i++) {
            const dik = dist[i][mid];
            if (dik === INF) continue;
            for (let j = 0; j < k; j++) {
                const nd = dik + dist[mid][j];
                if (nd < dist[i][j]) dist[i][j] = nd;
            }
        }
    }
    const lengths = Array.from(lengthsSet).sort((a, b) => a - b);
    const dp = new Array(n + 1).fill(INF);
    dp[0] = 0;
    for (let i = 0; i < n; i++) {
        if (dp[i] === INF) continue;
        if (source[i] === target[i] && dp[i] < dp[i + 1]) {
            dp[i + 1] = dp[i];
        }
        for (const L of lengths) {
            if (i + L > n) continue;
            const subS = source.slice(i, i + L);
            const subT = target.slice(i, i + L);
            if (nodeId.has(subS) && nodeId.has(subT)) {
                const u = nodeId.get(subS);
                const v = nodeId.get(subT);
                const d = dist[u][v];
                if (d < INF && dp[i] + d < dp[i + L]) {
                    dp[i + L] = dp[i] + d;
                }
            }
        }
    }
    return dp[n] < INF ? dp[n] : -1;
};
